import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as c,o as d,c as i,a as e,b as a,d as r,w as n,e as h}from"./app-cdacd89a.js";const s={},p=e("h3",{id:"前言",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#前言","aria-hidden":"true"},"#"),a(" 前言")],-1),l=e("p",null,"因為各券商手續費折讓比例與計算時的進位方式不同，為了更加準確的計算持有成本而設計「可輸入不同卷商功能」與為了計算精準誤差盡量趨近 0 而設計了手續費可選擇計算時的「進位方式」",-1),_=e("h3",{id:"如何知道手續費計算方式是麼進位",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#如何知道手續費計算方式是麼進位","aria-hidden":"true"},"#"),a(" 如何知道手續費計算方式是麼進位?")],-1),u=h('<h1 id="_1-元的誤差" tabindex="-1"><a class="header-anchor" href="#_1-元的誤差" aria-hidden="true">#</a> 1 元的誤差</h1><p>在以下幾種情況在計算過程中會有 1 元的誤差</p><ul><li><a href="#%E9%80%B2%E4%BD%8D%E5%95%8F%E9%A1%8C">進位問題</a></li><li><a href="#%E9%9B%B6%E8%82%A1">零股</a></li></ul><h3 id="進位問題" tabindex="-1"><a class="header-anchor" href="#進位問題" aria-hidden="true">#</a> 進位問題</h3><div class="hint-container tip"><p class="hint-container-title">這是屬於手續費進位問題</p></div><p>在「未實現損益」「已實現損益」</p><p>因為是多筆加總，因此加總後可能會有誤差屬正常現象</p><div class="hint-container info"><p class="hint-container-title">舉例</p><p>買進 已經四捨五入 賣出 也四捨五入</p><p>但實際損益的公式是全部一起算才四捨五入</p><p>買 1000 股 68.5 元 + 手續費 = <code>68524</code> 元</p><p>賣 1000 股 71.1 元 + 手續費 = <code>70862</code> 元</p><p>計算差額 = <code>2338</code> 元</p><hr><h4 id="實際上" tabindex="-1"><a class="header-anchor" href="#實際上" aria-hidden="true">#</a> 實際上</h4><p>買進 = <code>68524.4</code> 元</p><p>賣出 = <code>70861.6</code> 元</p><p>計算差額 = <code>2337.2</code> 元 &gt; 四捨五入 <code>2337</code> 元</p><p><code>2337</code> 元與 <code>2338</code> 元這裡就會產生 <code>1</code>元 的誤差</p></div><h3 id="零股" tabindex="-1"><a class="header-anchor" href="#零股" aria-hidden="true">#</a> 零股</h3><p>經詢問券商後，確認零股的部分這 1 元的差異是因為<br> 零股在交易時會因多次交易造成價差，且無法確定哪次交易會產生 1 元價差</p><div class="hint-container info"><p class="hint-container-title">舉例</p><p>對 A 檔股票下單 20.5 元 買 500 股<br> 搓合的過程可能是分三次成交<br> 100 股 + 250 股 + 150 股 = 500 股<br> 最後加總<br> 並在這過程中將會產生的價差 (原理同未實現損益)</p></div><blockquote><p>因此當此情況發生時，只能在交易紀錄的部分直接手動更改 支出 or 收入 欄位的數字</p></blockquote>',12);function f(b,m){const o=c("RouterLink");return d(),i("div",null,[p,l,_,e("p",null,[a("參考 "),r(o,{to:"/FQA/2022-11-16.html"},{default:n(()=>[a("常見問題Q&A > 如何知道券商手續費的計算進位方式?")]),_:1})]),u])}const B=t(s,[["render",f],["__file","2022-11-17.html.vue"]]);export{B as default};
